```ts
import { Effect, Ref, Clock, Duration } from "effect";

interface Bucket { readonly tokens: number; readonly lastRefillMs: number }

export const makeTokenBucket = (capacity: number, refillPerSec: number) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Bucket>({ tokens: capacity, lastRefillMs: 0 });
    const acquire = (): Effect.Effect<void> =>
      Effect.gen(function* () {
        while (true) {
          const now = yield* Clock.currentTimeMillis;
          const got = yield* Ref.modify(ref, (b) => {
            const add = Math.floor(((now - b.lastRefillMs) / 1000) * refillPerSec);
            const tokens = Math.min(capacity, b.tokens + Math.max(0, add));
            if (tokens <= 0) return [false, { tokens, lastRefillMs: now }];
            return [true, { tokens: tokens - 1, lastRefillMs: now }];
          });
          if (got) return;
          yield* Effect.sleep(Duration.millis(50));
        }
      });
    return { acquire } as const;
  });
```

```ts
import { Effect, Data } from "effect";

class PageError extends Data.TaggedError("PageError")<{ readonly cursor: string | null }> {}

interface Page {
  readonly items: ReadonlyArray<unknown>;
  readonly nextCursor: string | null;
}

declare const fetchPage: (cursor: string | null) => Effect.Effect<Page, PageError>;

export const crawlAll: Effect.Effect<ReadonlyArray<unknown>, PageError> =
  Effect.gen(function* () {
    const acc: unknown[] = [];
    let cursor: string | null = null;
    for (;;) {
      const page: Page = yield* fetchPage(cursor);
      acc.push(...page.items);
      if (page.nextCursor === null) return acc;
      cursor = page.nextCursor;
    }
  });
```

Mutation of `acc` is local to the generator — callers only see the returned `ReadonlyArray`.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type Shape = { _tag: 'Shape' };
type B64 = { _tag: 'B64' };
type Json = { _tag: 'Json' };

const splitThree = (raw: string): E.Either<Shape, [string, string, string]> => {
  const parts = raw.split('.');
  return parts.length === 3 ? E.right([parts[0], parts[1], parts[2]]) : E.left({ _tag: 'Shape' });
};

const decodeB64 = (s: string): E.Either<B64, string> => {
  try {
    return E.right(Buffer.from(s, 'base64url').toString('utf8'));
  } catch {
    return E.left({ _tag: 'B64' });
  }
};

const parseJson = (s: string): E.Either<Json, unknown> => {
  try {
    return E.right(JSON.parse(s) as unknown);
  } catch {
    return E.left({ _tag: 'Json' });
  }
};

export const decodePayload = (token: string): E.Either<Shape | B64 | Json, unknown> =>
  pipe(
    splitThree(token),
    E.chainW(([, body]) => decodeB64(body)),
    E.chainW(parseJson),
  );
