```ts
import { Effect, Console } from "effect";

interface ConfigFile { readonly url: string }
interface Client { readonly url: string; readonly id: number }

const openCfg = Effect.sync((): ConfigFile => ({ url: "https://api.test" }));
const closeCfg = () => Console.log("cfg closed");
const cfg = Effect.acquireRelease(openCfg, () => closeCfg());

const makeClient = (c: ConfigFile): Effect.Effect<Client> =>
  Effect.succeed({ url: c.url, id: 1 });
const closeClient = (cl: Client) => Console.log(`client ${cl.id} closed`);
const client = (c: ConfigFile) =>
  Effect.acquireRelease(makeClient(c), (cl) => closeClient(cl));

const program = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* cfg;
    const cl = yield* client(c);
    return cl.url;
  })
);

Effect.runPromise(program).then(console.log);
```

Client is released first (LIFO), then the config file — the natural reverse of acquisition order.

```ts
import { pipe } from 'fp-ts/function';

const parse = (n: unknown): string => String(n);
const trim = (s: string): string => s.trim();
const capitalise = (s: string): string => s.toUpperCase();
const prefix = (tag: string) => (s: string): string => `${tag}:${s}`;

export const format = (raw: unknown): string =>
  pipe(raw, parse, trim, capitalise, prefix('tag'));

// Nested equivalent — reads right-to-left, harder to scan:
export const formatNested = (raw: unknown): string =>
  prefix('tag')(capitalise(trim(parse(raw))));
```

With `pipe`, the data flows top-to-bottom in the same order as the reader's eye. The nested form forces you to mentally invert the call tree before you can describe what the function does.

```ts
import { Effect, Console } from "effect";

interface DbConn { readonly id: number; readonly close: () => void }

const connect = (): Effect.Effect<DbConn> =>
  Effect.sync(() => ({ id: Date.now(), close: () => console.log("disconnected") }));

const disconnect = (c: DbConn): Effect.Effect<void> =>
  Effect.sync(() => c.close());

// The pair: acquire + release.
const conn = Effect.acquireRelease(connect(), (c) => disconnect(c));

const query = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* conn;
    yield* Console.log(`SELECT 1 on conn ${c.id}`);
    return 1 as const;
  })
);

Effect.runPromise(query);
```

Without `Effect.scoped`, the effect still requires `Scope` in its `R` channel and cannot be executed directly. `scoped` closes the scope and runs the release regardless of outcome.

```ts
import { Effect, Data, Duration } from "effect";

class TimeoutErr extends Data.TaggedError("TimeoutErr")<{ readonly ms: number }> {}

const fetchPrimary: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("200 millis");
  return "primary-ok";
});

const timeoutAfter = (ms: number): Effect.Effect<never, TimeoutErr> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new TimeoutErr({ ms }));
  });

const program: Effect.Effect<string, TimeoutErr> = Effect.race(fetchPrimary, timeoutAfter(150));

Effect.runPromise(Effect.either(program)).then(console.log);
