```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type UrlErr =
  | { _tag: 'NoProto' }
  | { _tag: 'NoHost' }
  | { _tag: 'NoPath' };

const splitProto = (raw: string): E.Either<UrlErr, { proto: string; rest: string }> => {
  const i = raw.indexOf('://');
  return i > 0
    ? E.right({ proto: raw.slice(0, i), rest: raw.slice(i + 3) })
    : E.left({ _tag: 'NoProto' });
};

const splitHost = (
  r: { proto: string; rest: string },
): E.Either<UrlErr, { proto: string; host: string; rest: string }> => {
  const j = r.rest.indexOf('/');
  if (j <= 0) return E.left({ _tag: 'NoHost' });
  return E.right({ proto: r.proto, host: r.rest.slice(0, j), rest: r.rest.slice(j) });
};

const takePath = (
  r: { proto: string; host: string; rest: string },
): E.Either<UrlErr, { proto: string; host: string; path: string }> =>
  r.rest.length > 1
    ? E.right({ proto: r.proto, host: r.host, path: r.rest })
    : E.left({ _tag: 'NoPath' });

export const parseUrl = (raw: string) =>
  pipe(splitProto(raw), E.chainW(splitHost), E.chainW(takePath));
```

