import { Brand, Effect, Either } from "effect";
import { pipe } from "effect";

export type SemVer = string & Brand.Brand<"SemVer">;

const SEMVER_RE = /^(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)$/;

