  (s) => SEMVER_RE.test(s),
  (s) => Brand.error(`Not a semver: ${s}`),
);

declare const install: (pkg: string, v: SemVer) => Effect.Effect<void, Error>;

const liftSemVer = (e: Either.Either<SemVer, Brand.Brand.BrandErrors>): Effect.Effect<SemVer, Brand.Brand.BrandErrors> =>
  Either.isRight(e) ? Effect.succeed(e.right) : Effect.fail(e.left);

export const pin = (pkg: string, raw: string): Effect.Effect<void, Error | Brand.Brand.BrandErrors> =>
  pipe(
    liftSemVer(SemVer.either(raw)),
    Effect.flatMap((v) => install(pkg, v)),
  );
