import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type PositiveInt = number & Brand.Brand<"PositiveInt">;
export type UserId = number & Brand.Brand<"UserId">;
export type PositiveUserId = PositiveInt & UserId;

export const PositiveInt = Brand.refined<PositiveInt>(
  (n) => Number.isInteger(n) && n > 0,
  (n) => Brand.error(`Not positive int: ${n}`),
);
export const UserId = Brand.nominal<UserId>();

// Combine both constructors — `all` returns Either<BrandErrors, PositiveUserId>.
export const PositiveUserId = Brand.all(PositiveInt, UserId);

export const parse = (raw: number): Effect.Effect<PositiveUserId, Brand.Brand.BrandErrors> =>
  pipe(
    PositiveUserId.either(raw),
    (r) => r._tag === "Right" ? Effect.succeed(r.right) : Effect.fail(r.left),
  );
```

`Brand.all` intersects the nominal tags; only values that pass every refinement earn both tags simultaneously.

