import { Effect, Schedule } from "effect";

export const withRetry = <A, E, R>(
  eff: Effect.Effect<A, E, R>,
  maxRetries: number,
): Effect.Effect<A, E, R> => {
  const policy = Schedule.intersect(
    Schedule.jittered(Schedule.exponential("100 millis")),
    Schedule.recurs(maxRetries),
  );
  return Effect.retry(eff, policy);
};

// example wire-up
const flaky: Effect.Effect<number, Error> = Effect.fail(new Error("oops"));
export const run: Effect.Effect<number, Error> = withRetry(flaky, 3);
