import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface Card { number: string; expiry: string; cvv: string }
type Reason = { kind: 'number' } | { kind: 'expiry' } | { kind: 'cvv' };

const checkNumber = (c: Card): E.Either<Reason, Card> =>
  /^\d{13,19}$/.test(c.number) ? E.right(c) : E.left({ kind: 'number' });

const checkExpiry = (c: Card): E.Either<Reason, Card> =>
  /^(0[1-9]|1[0-2])\/\d{2}$/.test(c.expiry) ? E.right(c) : E.left({ kind: 'expiry' });

const checkCvv = (c: Card): E.Either<Reason, Card> =>
  /^\d{3,4}$/.test(c.cvv) ? E.right(c) : E.left({ kind: 'cvv' });

export const statusOf = (c: Card): number =>
  pipe(
    checkNumber(c),
    E.chainW(checkExpiry),
    E.chainW(checkCvv),
    E.fold(
      () => 422,
      () => 200,
    ),
  );
