```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseJson = (s: string): O.Option<unknown> => {
  try {
    return O.some(JSON.parse(s) as unknown);
  } catch {
    return O.none;
  }
};

const asRecord = (u: unknown): O.Option<Record<string, unknown>> =>
  typeof u === 'object' && u !== null ? O.some(u as Record<string, unknown>) : O.none;

const asString = (u: unknown): O.Option<string> =>
  typeof u === 'string' ? O.some(u) : O.none;

export const versionOf = (raw: string): string =>
  pipe(
    parseJson(raw),
    O.chain(asRecord),
    O.chain((r) => O.fromNullable(r.version)),
    O.chain(asString),
    O.getOrElse<string>(() => '0.0.0'),
  );
```

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

const nonEmpty = (s: string): E.Either<string, string> =>
  s.trim().length > 0 ? E.right(s) : E.left('email is required');

const hasAt = (s: string): E.Either<string, string> =>
  s.includes('@') ? E.right(s) : E.left("email must contain '@'");

const underMaxLen = (s: string): E.Either<string, string> =>
  s.length < 254 ? E.right(s) : E.left('email must be < 254 chars');

export const validateEmail = (s: string): E.Either<string, string> =>
  pipe(
    nonEmpty(s),
    E.chainW(hasAt),
    E.chainW(underMaxLen),
    E.mapLeft((msg) => `[email] ${msg}`),
  );
```

`E.chainW` is the widening variant — here all the error types happen to be `string`, but using `chainW` keeps the door open to different left types without a manual unification.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

class TooShort { readonly _tag = 'TooShort' as const }
class TooLong { readonly _tag = 'TooLong' as const }
class BadChars { readonly _tag = 'BadChars' as const }

const lengthOk = (s: string): E.Either<TooShort | TooLong, string> => {
  if (s.length < 3) return E.left(new TooShort());
  if (s.length > 20) return E.left(new TooLong());
  return E.right(s);
};

const alnumOnly = (s: string): E.Either<BadChars, string> =>
  /^[a-zA-Z0-9]+$/.test(s) ? E.right(s) : E.left(new BadChars());

export const normaliseUser = (raw: string): string =>
  pipe(
    lengthOk(raw),
    E.chainW(alnumOnly),
    E.map((s) => s.toLowerCase()),
    E.fold(
      (e) => `invalid:${e._tag}`,
      (u) => `ok:${u}`,
    ),
  );
```

```ts
import { Effect, Console } from "effect";

interface FileHandle { readonly path: string; readonly fd: number }

const openFile = (path: string): Effect.Effect<FileHandle, never, never> =>
  Effect.sync(() => ({ path, fd: Math.floor(Math.random() * 1_000_000) }));

const closeFile = (h: FileHandle): Effect.Effect<void> =>
  Console.log(`[close] ${h.path} (fd=${h.fd})`);

// acquireRelease returns Effect<A, E, Scope>; Effect.scoped eliminates Scope.
const fileResource = (path: string) =>
  Effect.acquireRelease(openFile(path), (h) => closeFile(h));

const program = Effect.scoped(
  Effect.gen(function* () {
    const h = yield* fileResource("/tmp/data.txt");
    yield* Console.log(`[use] reading ${h.path}`);
    return h.path;
  })
);

Effect.runPromise(program).then((r) => console.log("done:", r));
```

`Effect.acquireRelease` registers the finalizer in the current `Scope`. `Effect.scoped` closes that scope once the inner effect finishes, so the release runs even if the read step fails.

```ts
import { Effect, Console } from "effect";

interface Subscription { readonly topic: string; readonly next: () => string }

const subscribe = (topic: string): Effect.Effect<Subscription> =>
  Effect.sync(() => ({ topic, next: () => `msg from ${topic}` }));

const unsubscribe = (s: Subscription) => Console.log(`[ws] unsubscribed ${s.topic}`);

const subscription = (topic: string) =>
  Effect.acquireRelease(subscribe(topic), (s) => unsubscribe(s));

const readOne = Effect.scoped(
  Effect.gen(function* () {
    const s = yield* subscription("orders");
    const msg = s.next();
    yield* Console.log(msg);
    return msg;
  })
);

Effect.runPromise(readOne).then((m) => console.log("got:", m));
```

Server-side cleanup is guaranteed: whether the consumer finishes normally or fails mid-read, the unsubscribe is sent.

`Effect.catchTag(tagString, handler)` removes the matched tag from the error channel if the handler returns a success, or replaces it with the handler's own error type if the handler re-fails. The discriminator is the string `_tag`, not the class itself, so this works for both `Data.TaggedError` and hand-rolled `{ readonly _tag: "..." }` shapes.

```typescript
import { Effect, Data } from "effect";

class NotFound extends Data.TaggedError("NotFound")<{ readonly id: string }> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly role: string }> {}

const load = (id: string): Effect.Effect<string, NotFound | Forbidden> =>
  id === ""
    ? Effect.fail(new NotFound({ id }))
    : Effect.fail(new Forbidden({ role: "guest" }));

export const handled: Effect.Effect<string, Forbidden> = load("").pipe(
  Effect.catchTag("NotFound", (e) => Effect.succeed(`missing:${e.id}`))
);
```

The resulting `E` is `Forbidden` only — `NotFound` is gone because the handler's success drained it.

