import { pipe } from "effect";

// Effect v3: Brand.Brand<Name> replaces the hand-rolled unique-symbol phantom.
export type Tenant = string & Brand.Brand<"Tenant">;

export const Tenant = Brand.refined<Tenant>(
  (s) => /^[a-z][a-z0-9-]{1,62}$/.test(s),
  (s) => Brand.error(`Invalid tenant key: ${s}`),
);

declare const forTenant: <A>(t: Tenant, f: () => Effect.Effect<A, Error>) => Effect.Effect<A, Error>;

const liftTenant = (e: Either.Either<Tenant, Brand.Brand.BrandErrors>): Effect.Effect<Tenant, Brand.Brand.BrandErrors> =>
  Either.isRight(e) ? Effect.succeed(e.right) : Effect.fail(e.left);

export const run = <A>(raw: string, body: () => Effect.Effect<A, Error>): Effect.Effect<A, Error | Brand.Brand.BrandErrors> =>
  pipe(
    liftTenant(Tenant.either(raw)),
    Effect.flatMap((t) => forTenant(t, body)),
  );
