When an effect is interrupted (timeout, race loser, manual `Fiber.interrupt`), Effect runs each registered finalizer on the way out. `Effect.scoped` guarantees the finalizer runs regardless of exit reason — success, typed failure, defect, or interruption.

```ts
import { Effect, Console, Fiber } from "effect";

interface Session { readonly id: string }

const open = Effect.sync((): Session => ({ id: `s-${Date.now()}` }));
const close = (s: Session) => Console.log(`[closed] ${s.id}`);

const session = Effect.acquireRelease(open, (s) => close(s));

const run = Effect.gen(function* () {
  const fiber = yield* Effect.fork(
    Effect.scoped(
      Effect.gen(function* () {
        const s = yield* session;
        yield* Console.log(`[use] ${s.id}`);
        yield* Effect.never;
      })
    )
  );
  yield* Effect.sleep("15 millis");
  yield* Fiber.interrupt(fiber);
});

Effect.runPromise(run);
