import { pipe } from 'fp-ts/function';

interface UrlParts {
  readonly protocol: string;
  readonly host: string;
  readonly path: string;
  readonly query: string;
  readonly fragment: string;
}

const withProtocol = (p: string) => (u: UrlParts): UrlParts => ({ ...u, protocol: p });
const withHost = (h: string) => (u: UrlParts): UrlParts => ({ ...u, host: h });
const withPath = (p: string) => (u: UrlParts): UrlParts => ({ ...u, path: p });
const withQuery = (q: string) => (u: UrlParts): UrlParts => ({ ...u, query: q });
const withFragment = (f: string) => (u: UrlParts): UrlParts => ({ ...u, fragment: f });

const render = (u: UrlParts): string =>
  `${u.protocol}://${u.host}${u.path}${u.query ? `?${u.query}` : ''}${u.fragment ? `#${u.fragment}` : ''}`;

const empty: UrlParts = { protocol: '', host: '', path: '', query: '', fragment: '' };

export const buildUrl = (): string =>
  pipe(
    empty,
    withProtocol('https'),
    withHost('example.com'),
    withPath('/api/v1'),
    withQuery('id=42'),
    withFragment('top'),
    render
  );
