        port: port(c.port),
        db: str("db", c.db),
        region: str("region", c.region),
        ttl: ttl(c.ttl),
      },
      { mode: "validate" },
    ),
    Effect.mapError((rec) => {
      const entries: ReadonlyArray<Option.Option<CfgError>> = [rec.host, rec.port, rec.db, rec.region, rec.ttl];
