import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type SdkError =
  | { readonly _tag: 'RateLimited'; readonly retryAfterMs: number }
  | { readonly _tag: 'SdkFailure'; readonly cause: unknown };

interface RawSdkError { readonly code?: string; readonly retryAfter?: number }

const isRateLimited = (u: unknown): u is RawSdkError =>
  typeof u === 'object' && u !== null && (u as RawSdkError).code === 'RATE_LIMITED';

declare const sdk: { call: <A>(op: string) => Promise<A> };

