  TE.tryCatch(
    () => sdk.call<A>(op),
    (u): SdkError =>
      isRateLimited(u)
        ? { _tag: 'RateLimited', retryAfterMs: (u.retryAfter ?? 1) * 1000 }
        : { _tag: 'SdkFailure', cause: u }
  );

export const listUsers = (): TE.TaskEither<SdkError, ReadonlyArray<string>> =>
  pipe(
    callSdk<ReadonlyArray<{ name: string }>>('listUsers'),
    TE.map((xs) => xs.map((x) => x.name))
  );
