```ts
import { Effect } from "effect";

// v2 required an adapter argument so yield* could lift a plain Effect.
// v3 drops the adapter entirely — the generator takes zero args and
// yield* consumes an Effect<A, E, R> directly, binding A.
export const one: Effect.Effect<number> = Effect.gen(function* () {
  return yield* Effect.succeed(1);
});

// Equivalent chained form for reference:
export const oneAgain: Effect.Effect<number> = Effect.gen(function* () {
  const n = yield* Effect.succeed(1);
  return n;
});
```

Dropping the adapter makes the generator body read as ordinary TS — every `yield*` is just "await this effect".

A `Layer<ROut, E, RIn>` describes how to produce `ROut` given `RIn`. Leaves use `Layer.succeed` (pure) or `Layer.effect` (effectful construction). You compose with `Layer.merge` (union the outputs) and `Layer.provide(inner, deps)` (satisfy `inner`'s `RIn` from `deps`'s `ROut`). The final `Effect.provide(program, AppLayer)` closes the `R` channel entirely.

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly dsn: string }
const Config = Context.GenericTag<Config>("app/Config");

interface Db { readonly ping: () => Effect.Effect<boolean> }
const Db = Context.GenericTag<Db>("app/Db");

interface Cache { readonly size: () => Effect.Effect<number> }
const Cache = Context.GenericTag<Cache>("app/Cache");

const ConfigLive = Layer.succeed(Config, { dsn: "postgres://localhost/app" });

const DbLive = Layer.effect(
  Db,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { ping: () => Effect.succeed(cfg.dsn.length > 0) };
  })
);

const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    yield* Config; // reserved for future use
    return { size: () => Effect.succeed(0) };
  })
);

// Db and Cache both need Config. Merge the two dependents, then provide Config once.
const AppLayer = Layer.provide(Layer.merge(DbLive, CacheLive), ConfigLive);

const program = Effect.gen(function* () {
  const db = yield* Db;
  const c = yield* Cache;
  const ok = yield* db.ping();
  const n = yield* c.size();
  return { ok, n };
});

export const runnable = Effect.provide(program, AppLayer);
```

```ts
import { Effect, Data, Either } from "effect";

class Op1Error extends Data.TaggedError("Op1Error")<{ readonly reason: string }> {}
class Op2Error extends Data.TaggedError("Op2Error")<{ readonly reason: string }> {}

declare const op1: () => Effect.Effect<number, Op1Error>;
declare const op2: (n: number) => Effect.Effect<string, Op2Error>;

type OpError = Op1Error | Op2Error;

export const runBoth = (): Effect.Effect<
  { results: ReadonlyArray<number | string>; errors: ReadonlyArray<OpError> }
> =>
  Effect.gen(function* () {
    const a = yield* Effect.either(op1());
    const b = yield* Effect.either(op2(Either.isRight(a) ? a.right : 0));
    const results: Array<number | string> = [];
    const errors: OpError[] = [];
    if (Either.isRight(a)) results.push(a.right); else errors.push(a.left);
    if (Either.isRight(b)) results.push(b.right); else errors.push(b.left);
    return { results, errors };
  });
```

`Effect.either` converts a failure into a `Left`, letting the generator see both outcomes without short-circuiting on the first error.

