```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface SignUp { email: string; password: string }

const checkEmail = (s: SignUp): E.Either<string, SignUp> =>
  s.email.includes('@') ? E.right(s) : E.left('bad email');

const checkPassword = (s: SignUp): E.Either<string, SignUp> =>
  s.password.length >= 8 ? E.right(s) : E.left('short password');

const checkDistinct = (s: SignUp): E.Either<string, SignUp> =>
  s.email !== s.password ? E.right(s) : E.left('email=password');

export const describe = (s: SignUp): string =>
  pipe(
    checkEmail(s),
    E.chain(checkPassword),
    E.chain(checkDistinct),
    E.fold(
      (err) => `rejected: ${err}`,
      () => 'accepted',
    ),
  );
```

All the validators share `string` as their error type here, so plain `E.chain` is enough — use `E.chainW` only when the error types differ.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type PostError =
  | { readonly _tag: 'NetworkError'; readonly cause: unknown }
  | { readonly _tag: 'ParseError'; readonly body: string };

interface RawResponse { readonly raw: string; readonly ok: boolean }

const send = (url: string, payload: unknown): TE.TaskEither<PostError, RawResponse> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(url, {
        method: 'POST',
        body: JSON.stringify(payload),
        headers: { 'content-type': 'application/json' },
      });
      return { raw: await res.text(), ok: res.ok };
    },
    (u): PostError => ({ _tag: 'NetworkError', cause: u })
  );

const parse = (r: RawResponse): TE.TaskEither<PostError, unknown> =>
  TE.tryCatch(
    async () => JSON.parse(r.raw) as unknown,
    (): PostError => ({ _tag: 'ParseError', body: r.raw })
  );

export const postJson = (url: string, payload: unknown): TE.TaskEither<PostError, unknown> =>
  pipe(send(url, payload), TE.chain(parse));
```

Two `TE.tryCatch` blocks — one per distinct failure class — keeps each narrower small and focused on a single error tag.

```typescript
import { Effect, Data } from "effect";

class FileMissing extends Data.TaggedError("FileMissing")<{ readonly path: string }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

interface Config { readonly apiUrl: string }

const read = (path: string): Effect.Effect<string, FileMissing> =>
  path.endsWith(".json")
    ? Effect.succeed('{"apiUrl":"x"}')
    : Effect.fail(new FileMissing({ path }));

const parse = (raw: string): Effect.Effect<Config, ParseError> =>
  Effect.try({
    try: () => JSON.parse(raw) as Config,
    catch: () => new ParseError({ raw }),
  });

export const load = (path: string): Effect.Effect<Config, ParseError> =>
  Effect.gen(function* () {
    const raw = yield* read(path);
    return yield* parse(raw);
  }).pipe(
    Effect.catchTag("FileMissing", () => Effect.succeed({ apiUrl: "default" }))
  );
```

`FileMissing` is swallowed into a default value; `ParseError` stays in the channel because the caller probably wants to see malformed configs.

`Layer.merge(a, b)` is parallel composition: both `a` and `b` must produce their outputs, their requirements union, and their outputs union. Neither feeds the other.

`Layer.provide(inner, deps)` is vertical composition: `deps`' outputs satisfy `inner`'s requirements. `deps`' outputs are consumed, not re-exported.

```ts
import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: () => Effect.Effect<number> }
interface Logger { readonly info: (msg: string) => Effect.Effect<void> }
interface Audit { readonly write: (msg: string) => Effect.Effect<void> }

const Clock = Context.GenericTag<Clock>("app/Clock");
const Logger = Context.GenericTag<Logger>("app/Logger");
const Audit = Context.GenericTag<Audit>("app/Audit");

const ClockLive = Layer.succeed(Clock, { now: () => Effect.succeed(Date.now()) });
const LoggerLive = Layer.succeed(Logger, { info: (m) => Effect.sync(() => console.log(m)) });

// Audit needs Clock AND Logger.
const AuditLive = Layer.effect(
  Audit,
  Effect.gen(function* () {
    const clock = yield* Clock;
    const log = yield* Logger;
    return {
      write: (msg: string) =>
        Effect.gen(function* () {
          const t = yield* clock.now();
          yield* log.info(`${t} ${msg}`);
        }),
    };
  })
);

// Merge independent leaves, then provide them to Audit.
const Deps = Layer.merge(ClockLive, LoggerLive);
export const AppLayer = Layer.provide(AuditLive, Deps);
