import { pipe } from 'fp-ts/function';

const sum = (xs: ReadonlyArray<number>): number => xs.reduce((a, b) => a + b, 0);
const clampAt = (max: number) => (n: number): number => Math.min(n, max);
const toFixed = (digits: number) => (n: number): string => n.toFixed(digits);

export const summarise = (xs: ReadonlyArray<number>): string =>
  pipe(xs, sum, clampAt(100), toFixed(2));

// Equivalent without pipe, top-down reading order lost:
const nested = (xs: ReadonlyArray<number>): string =>
  toFixed(2)(clampAt(100)(sum(xs)));

export const _demo: readonly [string, string] = [
  summarise([10, 20, 30]),
  nested([10, 20, 30]),
];
