import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: () => number }
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Counter { readonly tick: () => Effect.Effect<number> }
const Counter = Context.GenericTag<Counter>("app/Counter");

// Pure value — Layer.succeed.
const ClockLive = Layer.succeed(Clock, { now: () => Date.now() });

// Effectful construction (allocate a closure over a mutable ref) — Layer.effect.
const CounterLive = Layer.effect(
  Counter,
  Effect.sync(() => {
    let n = 0;
    return { tick: () => Effect.sync(() => ++n) };
