import { Effect, Option } from "effect";
import { pipe } from "effect";

export interface Shipping { readonly weightKg: number; readonly lengthCm: number; readonly widthCm: number }

class ShipErr { readonly _tag = "ShipErr" as const; constructor(readonly field: keyof Shipping, readonly msg: string) {} }

const vWeight = (n: number): Effect.Effect<number, ShipErr> =>
  n > 0 && n <= 30 ? Effect.succeed(n) : Effect.fail(new ShipErr("weightKg", "must be (0, 30]"));
const vLen = (n: number): Effect.Effect<number, ShipErr> =>
  n > 0 && n <= 120 ? Effect.succeed(n) : Effect.fail(new ShipErr("lengthCm", "must be (0, 120]"));
const vWid = (n: number): Effect.Effect<number, ShipErr> =>
  n > 0 && n <= 120 ? Effect.succeed(n) : Effect.fail(new ShipErr("widthCm", "must be (0, 120]"));

export const validate = (s: Shipping): Effect.Effect<Shipping, ReadonlyArray<ShipErr>> =>
  pipe(
    Effect.all(
      { w: vWeight(s.weightKg), l: vLen(s.lengthCm), wd: vWid(s.widthCm) },
      { mode: "validate", concurrency: "unbounded" },
    ),
    Effect.mapError((rec) => {
      const entries: ReadonlyArray<Option.Option<ShipErr>> = [rec.w, rec.l, rec.wd];
      return entries.flatMap((e) => Option.isSome(e) ? [e.value] : []);
    }),
    Effect.map(() => s),
  );
