```ts
import { Effect, Data } from "effect";

interface Header { readonly count: number }

class HeaderError extends Data.TaggedError("HeaderError")<{ readonly raw: string }> {}
class BodyError extends Data.TaggedError("BodyError")<{ readonly index: number }> {}

declare const readLine: () => Effect.Effect<string>;

const parseHeader = (raw: string): Effect.Effect<Header, HeaderError> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0
    ? Effect.succeed({ count: n })
    : Effect.fail(new HeaderError({ raw }));
};

export const parseMessage = (): Effect.Effect<
  { header: Header; body: ReadonlyArray<string> },
  HeaderError | BodyError
> =>
  Effect.gen(function* () {
    const headerRaw = yield* readLine();
    const header = yield* parseHeader(headerRaw);
    const body: string[] = [];
    for (let i = 0; i < header.count; i++) {
      const line = yield* readLine();
      if (line.length === 0) return yield* Effect.fail(new BodyError({ index: i }));
      body.push(line);
    }
    return { header, body };
  });
```

`pipe(x, f, g, h)` is the smallest possible primitive that expresses sequential data-first composition. Every other fp-ts combinator — `map`, `chain`, `filter`, `ap` — is designed to slot into a pipe, because pipe-friendly APIs compose trivially without naming intermediate values. That consistency is why fp-ts calls `pipe` canonical.

