import { Effect, Data } from "effect";

class ReadError extends Data.TaggedError("ReadError")<{}> {}
class PublishError extends Data.TaggedError("PublishError")<{ readonly id: string }> {}
class MarkError extends Data.TaggedError("MarkError")<{ readonly id: string }> {}

interface OutboxRow { readonly id: string; readonly topic: string; readonly payload: unknown }

declare const readPending: () => Effect.Effect<ReadonlyArray<OutboxRow>, ReadError>;
declare const publish: (r: OutboxRow) => Effect.Effect<void, PublishError>;
declare const markSent: (id: string) => Effect.Effect<void, MarkError>;

export const drainOutbox: Effect.Effect<number, ReadError | PublishError | MarkError> =
  Effect.gen(function* () {
    const rows = yield* readPending();
    let sent = 0;
    for (const row of rows) {
      yield* publish(row);
      yield* markSent(row.id);
      sent += 1;
    }
    return sent;
  });
```

If `publish` succeeds but `markSent` fails, the overall effect fails — the next drain retries the row, which is why publishers must be idempotent.

