const inc = (n: number): number => n + 1;
const dbl = (n: number): number => n * 2;
const str = (n: number): string => `value=${n}`;

// Data-first: apply the composition to a concrete argument.
export const applyToTen: string = pipe(10, inc, dbl, str);

// Point-free: build a reusable composed function with `flow`.
