import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const at = <A>(xs: ReadonlyArray<A>, i: number): O.Option<A> =>
  i >= 0 && i < xs.length ? O.some(xs[i]) : O.none;

export const thirdUpper = (xs: ReadonlyArray<string>): string =>
  pipe(
    at(xs, 2),
    O.map((s) => s.toUpperCase()),
    O.getOrElse<string>(() => ''),
  );
