```ts
import { Effect, Console } from "effect";

interface Lock { readonly name: string; release: () => void }

const acquireLock = (name: string): Effect.Effect<Lock> =>
  Effect.sync(() => ({ name, release: () => console.log(`released ${name}`) }));

const lock = (name: string) =>
  Effect.acquireRelease(acquireLock(name), (l) => Effect.sync(() => l.release()));

const critical = Effect.scoped(
  Effect.gen(function* () {
    const l = yield* lock("inventory");
    yield* Console.log(`[critical] holding ${l.name}`);
    return "done" as const;
  })
);

Effect.runPromise(critical).then(console.log);
