import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = { kind: 'parse' };
type NormErr = { kind: 'norm' };

const parse = (s: string): E.Either<ParseErr, string> =>
  s.trim().length > 0 ? E.right(s.trim()) : E.left({ kind: 'parse' });

const normalise = (s: string): E.Either<NormErr, string> =>
  /^[a-z0-9-]+$/.test(s) ? E.right(s) : E.left({ kind: 'norm' });

export const run = (input: string): string =>
  pipe(
    parse(input),
    E.chainW(normalise),
    E.match(
      (e) => `error:${e.kind}`,
      (ok) => `ok:${ok}`,
    ),
  );
```

`E.match` is `E.fold` by another name — both collapse `Either<E, A>` to a single `B` by handling both sides.

