class QuotaExceeded extends Data.TaggedError("QuotaExceeded")<{ readonly userId: string }> {}
class PersistError extends Data.TaggedError("PersistError")<{ readonly cause: string }> {}

interface RawReq { readonly userId: string; readonly body: unknown }
interface Valid { readonly userId: string; readonly payload: { readonly kind: string } }
interface Saved { readonly id: string }

declare const parse: (r: RawReq) => Effect.Effect<Valid, SchemaError>;
declare const checkQuota: (userId: string) => Effect.Effect<void, QuotaExceeded>;
declare const persist: (v: Valid) => Effect.Effect<Saved, PersistError>;
declare const emitAudit: (s: Saved, userId: string) => Effect.Effect<void>;

export const handle = (
  r: RawReq,
): Effect.Effect<Saved, SchemaError | QuotaExceeded | PersistError> =>
  Effect.gen(function* () {
    const v = yield* parse(r);
    yield* checkQuota(v.userId);
    const saved = yield* persist(v);
    yield* emitAudit(saved, v.userId);
    return saved;
  });
