```ts
import { Effect, Exit } from "effect";

interface SagaStep<E> {
  readonly name: string;
  readonly action: Effect.Effect<void, E>;
  readonly compensate: Effect.Effect<void>;
}

export const runSaga = <E>(
  steps: ReadonlyArray<SagaStep<E>>,
): Effect.Effect<void, E> =>
  Effect.gen(function* () {
    const done: SagaStep<E>[] = [];
    const exit = yield* Effect.exit(
      Effect.gen(function* () {
        for (const step of steps) {
          yield* step.action;
          done.push(step);
        }
      }),
    );
    if (Exit.isSuccess(exit)) return;
    for (const s of done.reverse()) {
      yield* Effect.orDie(s.compensate);
    }
    return yield* Effect.failCause(exit.cause);
  });
```

The inner `Effect.exit` isolates partial progress; compensations run on the reversed `done` list.

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

`E.chain` is monadic: the second step only runs if the first was `Right`. Validation is applicative: both steps always run, so both errors can accumulate via a semigroup on the Left.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { sequenceT } from "fp-ts/Apply";

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;
const bad = (m: Err): V<never> => E.left([m] as RNEA.ReadonlyNonEmptyArray<Err>);

const vInt = (n: number): V<number> => Number.isInteger(n) ? E.right(n) : bad("not int");
const vPos = (n: number): V<number> => n > 0 ? E.right(n) : bad("not positive");

const appVal = E.getApplicativeValidation(RNEA.getSemigroup<Err>());

export const validatePair = (a: number, b: number): V<readonly [number, number]> =>
  pipe(sequenceT(appVal)(vInt(a), vPos(b)));

// validatePair(1.5, -1) returns Left(["not int", "not positive"]).
