```ts
import { Effect } from "effect";
import { pipe } from "effect";

class Err { readonly _tag = "Err" as const; constructor(readonly index: number, readonly msg: string) {} }

const check = (idx: number, s: string): Effect.Effect<string, Err> =>
  s.length > 0 ? Effect.succeed(s) : Effect.fail(new Err(idx, "empty"));

export const validateAll = (items: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<string>, ReadonlyArray<Err>> =>
  pipe(
    Effect.partition(items, (s, i) => check(i, s), { concurrency: 4 }),
    Effect.flatMap(([errs, ok]) => errs.length > 0 ? Effect.fail(errs) : Effect.succeed(ok)),
  );
```

`Effect.partition(iter, f, { concurrency })` runs every `f` to completion (collecting all failures on the left) while capping parallelism. Unlike `Effect.forEach`, a failure does not cancel siblings.

