    Effect.gen(function* () {
      const handle = yield* tryAcquire(key);
      const result = yield* Effect.exit(body);
      yield* release(key, handle.token);
      if (Exit.isFailure(result)) return yield* Effect.failCause(result.cause);
      return result.value;
