import * as O from 'fp-ts/Option';

const afterAt = (s: string): O.Option<string> => {
  const i = s.indexOf('@');
  return i >= 0 ? O.some(s.slice(i + 1)) : O.none;
};

export const emailDomain = (input: string | null | undefined): string =>
  pipe(
    O.fromNullable(input),
    O.chain(afterAt),
    O.map((d) => d.toLowerCase()),
    O.getOrElse<string>(() => 'anonymous'),
  );
```

