import { Effect, Data } from "effect";

class BadBody extends Data.TaggedError("BadBody")<{ readonly msg: string }> {}
class Unauthenticated extends Data.TaggedError("Unauthenticated")<{}> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly need: string }> {}
class HandlerError extends Data.TaggedError("HandlerError")<{ readonly cause: string }> {}

interface Req { readonly headers: Readonly<Record<string, string>>; readonly rawBody: string }
interface Body { readonly action: string }
interface Principal { readonly userId: string; readonly scopes: ReadonlyArray<string> }
interface Result { readonly ok: true; readonly data: unknown }
interface Res { readonly status: number; readonly body: string }

declare const parseBody: (raw: string) => Effect.Effect<Body, BadBody>;
declare const authenticate: (h: Readonly<Record<string, string>>) => Effect.Effect<Principal, Unauthenticated>;
declare const authorize: (p: Principal, action: string) => Effect.Effect<void, Forbidden>;
declare const runHandler: (p: Principal, b: Body) => Effect.Effect<Result, HandlerError>;

export const handleRequest = (
  req: Req,
): Effect.Effect<Res, BadBody | Unauthenticated | Forbidden | HandlerError> =>
  Effect.gen(function* () {
    const body = yield* parseBody(req.rawBody);
    const principal = yield* authenticate(req.headers);
    yield* authorize(principal, body.action);
    const out = yield* runHandler(principal, body);
    return { status: 200, body: JSON.stringify(out) } satisfies Res;
  });
```

