interface Person { readonly name: string; readonly age: number }

class DecodeError { readonly _tag = "DecodeError" as const; constructor(readonly path: string, readonly msg: string) {} }

const isString = (path: string, v: unknown): Effect.Effect<string, DecodeError> =>
  typeof v === "string" ? Effect.succeed(v) : Effect.fail(new DecodeError(path, "expected string"));
const isNumber = (path: string, v: unknown): Effect.Effect<number, DecodeError> =>
  typeof v === "number" ? Effect.succeed(v) : Effect.fail(new DecodeError(path, "expected number"));

const toRecord = (u: unknown): Effect.Effect<Record<string, unknown>, ReadonlyArray<DecodeError>> =>
  typeof u === "object" && u !== null && !Array.isArray(u)
    ? Effect.succeed(u as Record<string, unknown>)
    : Effect.fail([new DecodeError("$", "expected object")]);

export const decodePerson = (raw: unknown): Effect.Effect<Person, ReadonlyArray<DecodeError>> =>
  pipe(
    toRecord(raw),
    Effect.flatMap((obj) =>
      pipe(
        Effect.all({ name: isString("name", obj.name), age: isNumber("age", obj.age) }, { mode: "validate" }),
        Effect.mapError((rec) => [rec.name, rec.age].flatMap((o) => Option.isSome(o) ? [o.value] : [])),
      ),
    ),
  );
