import { Effect, Console, Ref } from "effect";

interface Tx { readonly id: string; readonly status: Ref.Ref<"open" | "committed"> }

const beginTx: Effect.Effect<Tx> = Effect.gen(function* () {
  const status = yield* Ref.make<"open" | "committed">("open");
  return { id: `tx-${Date.now()}`, status };
});

const finishTx = (tx: Tx): Effect.Effect<void> =>
  Effect.gen(function* () {
    const s = yield* Ref.get(tx.status);
    yield* s === "committed" ? Console.log(`COMMIT ${tx.id}`) : Console.log(`ROLLBACK ${tx.id}`);
  });

const transaction = Effect.acquireRelease(beginTx, (tx) => finishTx(tx));

const writeAndCommit = Effect.scoped(
  Effect.gen(function* () {
    const tx = yield* transaction;
    yield* Console.log(`INSERT ... in ${tx.id}`);
    yield* Ref.set(tx.status, "committed");
    return "ok" as const;
  })
);

Effect.runPromise(writeAndCommit).then(console.log);
```

The release reads the tx's status Ref — if the body set it to `committed`, commit; otherwise (failure, interruption) roll back.

