import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface Form { id: string; email: string; age: number }

type Err = { tag: 'id' } | { tag: 'email' } | { tag: 'age' };

const checkId = (f: Form): E.Either<Err, Form> =>
  f.id.length > 0 ? E.right(f) : E.left({ tag: 'id' });

const checkEmail = (f: Form): E.Either<Err, Form> =>
  f.email.includes('@') ? E.right(f) : E.left({ tag: 'email' });

const checkAge = (f: Form): E.Either<Err, Form> =>
  f.age >= 13 ? E.right(f) : E.left({ tag: 'age' });

export const summarise = (f: Form): string =>
  pipe(
    checkId(f),
    E.chain(checkEmail),
    E.chain(checkAge),
    E.match(
      (e) => `first-failure:${e.tag}`,
      () => 'all-valid',
    ),
  );
