class BadPayload extends Data.TaggedError("BadPayload")<{ readonly msg: string }> {}
class UnknownSubscription extends Data.TaggedError("UnknownSubscription")<{ readonly id: string }> {}
class DispatchError extends Data.TaggedError("DispatchError")<{ readonly cause: string }> {}

interface RawHook { readonly signature: string; readonly body: string; readonly subId: string }
interface Payload { readonly event: string }
interface Subscription { readonly id: string; readonly url: string }

declare const verifySig: (h: RawHook) => Effect.Effect<void, BadSignature>;
declare const parsePayload: (raw: string) => Effect.Effect<Payload, BadPayload>;
declare const findSub: (id: string) => Effect.Effect<Subscription, UnknownSubscription>;
declare const dispatch: (s: Subscription, p: Payload) => Effect.Effect<void, DispatchError>;

export const receiveHook = (
  h: RawHook,
): Effect.Effect<void, BadSignature | BadPayload | UnknownSubscription | DispatchError> =>
  Effect.gen(function* () {
    yield* verifySig(h);
    const payload = yield* parsePayload(h.body);
    const sub = yield* findSub(h.subId);
    yield* dispatch(sub, payload);
  });
