import { Effect, Option } from "effect";
import { pipe } from "effect";

interface Card { readonly number: string; readonly cvv: string; readonly expiry: string }

class CardError { readonly _tag = "CardError" as const; constructor(readonly field: keyof Card, readonly msg: string) {} }

const vNumber = (s: string): Effect.Effect<string, CardError> =>
  /^\d{13,19}$/.test(s) ? Effect.succeed(s) : Effect.fail(new CardError("number", "must be 13-19 digits"));
const vCvv = (s: string): Effect.Effect<string, CardError> =>
  /^\d{3,4}$/.test(s) ? Effect.succeed(s) : Effect.fail(new CardError("cvv", "must be 3-4 digits"));
const vExpiry = (s: string): Effect.Effect<string, CardError> =>
  /^(0[1-9]|1[0-2])\/\d{2}$/.test(s) ? Effect.succeed(s) : Effect.fail(new CardError("expiry", "MM/YY required"));

export const validateCard = (c: Card): Effect.Effect<Card, ReadonlyArray<CardError>> =>
  pipe(
    Effect.all([vNumber(c.number), vCvv(c.cvv), vExpiry(c.expiry)], { mode: "validate" }),
    Effect.mapError((opts) => opts.flatMap((o) => Option.isSome(o) ? [o.value] : [])),
    Effect.map(([number, cvv, expiry]) => ({ number, cvv, expiry })),
  );
```

With `mode: "validate"` every field validator runs; the error channel becomes `ReadonlyArray<Option<CardError>>`, and `Option.isSome` filters out the `None` slots (the validators that succeeded) before failing.

