import { Effect, Console } from "effect";

interface Cache { readonly get: (k: string) => string | undefined; readonly size: () => number }

const buildCache = Effect.sync((): Cache => {
  const store = new Map<string, string>();
  store.set("hello", "world");
  return { get: (k) => store.get(k), size: () => store.size };
});

const teardownCache = (c: Cache) => Console.log(`cache torn down (size=${c.size()})`);

const cache = Effect.acquireRelease(buildCache, (c) => teardownCache(c));

const program = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* cache;
    return c.get("hello") ?? "MISS";
  })
);

Effect.runPromise(program).then(console.log);
```

