  Number.isInteger(n) && n >= 1 ? Effect.succeed(n) : Effect.fail(new QErr("page", "must be >= 1"));
const vPageMax = (n: number): Effect.Effect<number, QErr> =>
  n <= 10_000 ? Effect.succeed(n) : Effect.fail(new QErr("page", "paging too deep"));
const vSizePos = (n: number): Effect.Effect<number, QErr> =>
  Number.isInteger(n) && n >= 1 ? Effect.succeed(n) : Effect.fail(new QErr("size", "must be >= 1"));
const vSizeMax = (n: number): Effect.Effect<number, QErr> =>
  n <= 100 ? Effect.succeed(n) : Effect.fail(new QErr("size", "too large"));

