import { Effect, Option, Ref, HashMap } from "effect";

export const makeMemoCache = <K, V>() =>
  Effect.gen(function* () {
    const store = yield* Ref.make<HashMap.HashMap<K, V>>(HashMap.empty());
    const get = (key: K, load: (k: K) => Effect.Effect<V>): Effect.Effect<V> =>
      Effect.gen(function* () {
        const map = yield* Ref.get(store);
        const hit = HashMap.get(map, key);
        if (Option.isSome(hit)) return hit.value;
        const v = yield* load(key);
        yield* Ref.update(store, (m) => HashMap.set(m, key, v));
        return v;
      });
    return { get } as const;
  });
