`Effect.all(record, { mode: "validate" })` is the Effect-native analogue: all validators run; on failure the error channel is a record whose values are `Option<Err>`, and `Option.isSome` filters the `None` slots.

Branded types attach a phantom tag to a primitive so two structurally identical strings (e.g. `UserId` and `AccountId`) become non-assignable at compile time. `Brand.nominal` is the zero-runtime-cost constructor; `Brand.refined` adds a predicate.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type UserId = string & Brand.Brand<"UserId">;
export type AccountId = string & Brand.Brand<"AccountId">;

export const UserId = Brand.nominal<UserId>();
export const AccountId = Brand.nominal<AccountId>();

declare const lookup: (u: UserId) => Effect.Effect<{ name: string }, Error>;

export const go = (raw: string): Effect.Effect<string, Error> =>
  pipe(
    lookup(UserId(raw)),
    Effect.map((u) => u.name),
  );

// lookup(AccountId("a_1")) does NOT compile — mis-typed id caught statically.
```

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly host: string }
interface Logger { readonly info: (msg: string) => Effect.Effect<void> }
interface Main { readonly run: () => Effect.Effect<void> }

const Config = Context.GenericTag<Config>("app/Config");
const Logger = Context.GenericTag<Logger>("app/Logger");
const Main = Context.GenericTag<Main>("app/Main");

const ConfigLive = Layer.succeed(Config, { host: "localhost" });
const LoggerLive = Layer.effect(
  Logger,
  Effect.succeed({ info: (m: string) => Effect.sync(() => console.log(m)) })
);
const MainLive = Layer.effect(
  Main,
  Effect.gen(function* () {
    const cfg = yield* Config;
    const log = yield* Logger;
    return { run: () => log.info(`main on ${cfg.host}`) };
  })
);

// v3 positional form; inner deps go in the second argument.
export const AppLayer = Layer.provide(MainLive, Layer.merge(ConfigLive, LoggerLive));
```

Instead of chaining `Layer.provide` once per dep, merge the dependencies into one layer and provide it in a single call — positional arguments in v3.

```ts
export type Result<T, E> =
  | { readonly ok: true; readonly value: T }
  | { readonly ok: false; readonly error: E };

export const ok = <T>(value: T): Result<T, never> => ({ ok: true, value });
export const err = <E>(error: E): Result<never, E> => ({ ok: false, error });

export function map<T, U, E>(r: Result<T, E>, f: (t: T) => U): Result<U, E> {
  return r.ok ? ok(f(r.value)) : r;
}
```

The `readonly` tags prevent callers from mutating the discriminator. `ok` returns `Result<T, never>` and `err` returns `Result<never, E>`, which flow cleanly through `map` without widening. `map` short-circuits on the err branch — it's the same semantics as `fp-ts` Either's `map`.

```ts
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import type { Semigroup } from "fp-ts/Semigroup";

interface ErrBag { readonly messages: ReadonlyArray<string> }

const semigroupErrBag: Semigroup<ErrBag> = {
  concat: (x, y) => ({ messages: [...x.messages, ...y.messages] }),
};

type V<A> = E.Either<ErrBag, A>;
const bad = (m: string): V<never> => E.left({ messages: [m] });

const vPos = (n: number): V<number> => n > 0 ? E.right(n) : bad("must be positive");
const vEven = (n: number): V<number> => n % 2 === 0 ? E.right(n) : bad("must be even");

// Accumulate Lefts by concatenating via the custom semigroup.
const combine2 = <A, B>(a: V<A>, b: V<B>): V<readonly [A, B]> => {
  if (E.isLeft(a) && E.isLeft(b)) return E.left(semigroupErrBag.concat(a.left, b.left));
  if (E.isLeft(a)) return a;
  if (E.isLeft(b)) return b;
  return E.right([a.right, b.right] as const);
};

export const validate = (n: number): V<number> =>
  pipe(combine2(vPos(n), vEven(n)), E.map(() => n));

// validate(-3) returns Left({ messages: ["must be positive", "must be even"] })
// because the custom semigroup concatenates both messages into one bag.
export const demo: V<number> = validate(-3);

// Seed a trivial E.chain usage so the file still exercises the chain combinator.
const _seed: V<number> = pipe(E.right<ErrBag, number>(0), E.chain((n) => E.right(n)));
void _seed;
```

