import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { sequenceS } from "fp-ts/Apply";

type Err = { readonly field: string; readonly msg: string };
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;

const mkErr = (field: string, msg: string): Err => ({ field, msg });
const bad = (e: Err): V<never> => E.left([e] as RNEA.ReadonlyNonEmptyArray<Err>);

const vUser = (s: string): V<string> => /^[a-z][a-z0-9_]{2,20}$/.test(s) ? E.right(s) : bad(mkErr("username", "invalid"));
const vEmail = (s: string): V<string> => s.includes("@") ? E.right(s) : bad(mkErr("email", "missing @"));
const vPw = (s: string): V<string> => s.length >= 8 ? E.right(s) : bad(mkErr("password", "too short"));
const vConfirm = (pw: string, c: string): V<string> => pw === c ? E.right(c) : bad(mkErr("confirm", "mismatch"));

const appVal = E.getApplicativeValidation(RNEA.getSemigroup<Err>());

export interface Form { readonly username: string; readonly email: string; readonly password: string; readonly confirm: string }

export const validateForm = (f: Form): V<Form> =>
  sequenceS(appVal)({
    username: vUser(f.username),
    email: vEmail(f.email),
    password: vPw(f.password),
    confirm: vConfirm(f.password, f.confirm),
  });

export const demo: V<Form> = pipe(
  validateForm({ username: "A", email: "no", password: "x", confirm: "y" }),
);
