import { Effect, Schedule, pipe } from "effect";

// `Schedule.recurs(n)` caps on attempt count; `Schedule.upTo(d)` caps on
// total elapsed time. Use attempt cap for user-visible operations and time
// cap for background work where unbounded attempts could starve resources.

const task: Effect.Effect<number, Error> = Effect.fail(new Error("flaky"));

