```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseError = { kind: 'parse'; raw: string };
type RangeError = { kind: 'range'; value: number };

const parseIntStrict = (s: string): E.Either<ParseError, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? E.left({ kind: 'parse', raw: s }) : E.right(n);
};

const inRange = (n: number): E.Either<RangeError, number> =>
  n >= 0 && n <= 100 ? E.right(n) : E.left({ kind: 'range', value: n });

export const parsePercent = (
  s: string,
): E.Either<ParseError | RangeError, number> =>
  pipe(parseIntStrict(s), E.chainW(inRange));
```

`E.chainW` widens the left channel to the union of both error types. Plain `E.chain` would require both sides to share an error type.

