```ts
import { Effect, Data, Console } from "effect";

class PoolExhausted extends Data.TaggedError("PoolExhausted")<{ readonly size: number }> {}

interface Pool { readonly size: number; readonly lease: () => Effect.Effect<number> }

const acquirePool = (size: number): Effect.Effect<Pool, PoolExhausted> =>
  size <= 0
    ? Effect.fail(new PoolExhausted({ size }))
    : Effect.succeed({ size, lease: () => Effect.succeed(Math.floor(Math.random() * size)) });

const releasePool = (p: Pool) => Console.log(`drain pool(size=${p.size})`);

const pool = (n: number) =>
  Effect.acquireRelease(acquirePool(n), (p) => releasePool(p));

const job = Effect.scoped(
  Effect.gen(function* () {
    const p = yield* pool(4);
    const id = yield* p.lease();
    return id;
  })
);

Effect.runPromise(job).then((n) => console.log("leased", n));
```

The only error surfaced to the caller is `PoolExhausted`; the release runs unconditionally through `Effect.scoped`.

Insert `Effect.tap` between the two steps — logging returns its own effect, but `tap` discards it and keeps the `ChargeReceipt` flowing into `persistOrder`.

```ts
import { Effect } from "effect";

interface Order { readonly id: string; readonly cents: number }
interface ChargeReceipt { readonly txId: string; readonly cents: number }
interface Persisted { readonly orderId: string; readonly txId: string }

declare const chargeCard: (o: Order) => Effect.Effect<ChargeReceipt>;
declare const persistOrder: (r: ChargeReceipt) => Effect.Effect<Persisted>;

export const placeOrder = (o: Order): Effect.Effect<Persisted> =>
  chargeCard(o).pipe(
    Effect.tap((r) => Effect.logInfo(`charged ${r.cents}c as ${r.txId}`)),
    Effect.flatMap(persistOrder),
  );
