});
const StoreLive = Layer.effect(Store, Effect.succeed({ put: (_k: string, _v: string) => Effect.void }));

// Production wiring.
const AppLayer = Layer.merge(LoggerLive, StoreLive);

// Test override: silent Logger replaces LoggerLive, StoreLive is unchanged.
const LoggerTest = Layer.succeed(Logger, { info: (_msg: string) => Effect.void });
export const TestLayer = Layer.merge(LoggerTest, StoreLive);

export const program = Effect.gen(function* () {
  const log = yield* Logger;
  const store = yield* Store;
  yield* log.info("writing");
  yield* store.put("k", "v");
});

export const live = Effect.provide(program, AppLayer);
export const test = Effect.provide(program, TestLayer);
