import { Effect } from "effect";

class JobError {
  readonly _tag = "JobError" as const;
  constructor(readonly id: number) {}
}

const job = (id: number): Effect.Effect<number, JobError> =>
  id === 7 ? Effect.fail(new JobError(id)) : Effect.succeed(id);

